            const [x2, y2] = points[j];
            let slope: string;

            if (x1 === x2) {
                slope = "inf"; // vertical line
            } else {
                const dy = y2 - y1;
                const dx = x2 - x1;
                const gcd = Math.gcd(Math.abs(dy), Math.abs(dx));
                const reducedDy = dy / gcd;
                const reducedDx = dx / gcd;
                slope = `${reducedDy},${reducedDx}`;
            }

            if (!slopeMap.has(slope)) {
                slopeMap.set(slope, []);
            }
            slopeMap.get(slope)!.push(i);
        }
    }

    let count = 0;

    for (const [slope, indices] of slopeMap.entries()) {
        if (indices.length < 2) continue;

        const len = indices.length;
        for (let i = 0; i < len; i++) {
