                const p2 = indices[j];
                const [x1, y1] = points[p1];
                const [x2, y2] = points[p2];

                // Find pairs of points that form a line with the same slope
                for (let k = 0; k < len; k++) {
                    if (k === i || k === j) continue;
                    const p3 = indices[k];
                    const [x3, y3] = points[p3];

                    for (let l = k + 1; l < len; l++) {
                        if (l === i || l === j || l === k) continue;
                        const p4 = indices[l];
                        const [x4, y4] = points[p4];

                        // Check if the lines p1-p2 and p3-p4 are parallel
                        // and if the lines p1-p3 and p2-p4 are parallel
                        // or p1-p4 and p2-p3 are parallel
                        const isParallel = (a: number[], b: number[]): boolean => {
                            const [x1, y1] = a;
                            const [x2, y2] = b;
                            const [x3, y3] = points[p1];
                            const [x4, y4] = points[p2];

