                            const dy1 = y2 - y1;
                            const dx2 = x4 - x3;
                            const dy2 = y4 - y3;

                            return dx1 * dy2 === dx2 * dy1;
                        };

                        if (isParallel([x1, y1], [x2, y2]) && isParallel([x3, y3], [x4, y4])) {
